def proxy_openai_chat_sse():
    upstream_url = f"{OLLAMA_HOST}/v1/chat/completions"
    
    def sse_wrapper():
        with requests.post(upstream_url, data=request.get_data(), stream=True) as r:
            for line in r.iter_lines():
                if line:
                    # If upstream sends SSE, pass through. If NDJSON, wrap it.
                    decoded = line.decode('utf-8')
                    if decoded.startswith('data:'):
                        yield line + b'\n\n'
                    else:
                        yield f"data: {decoded}\n\n".encode()
                # OpenAI SSE ends with [DONE]
                # Ollama doesn't send [DONE], so we add it on stream end
            yield b"data: [DONE]\n\n"
    
    return Response(sse_wrapper(), mimetype='text/event-stream', 
                   headers={'Cache-Control': 'no-cache', 'X-Accel-Buffering': 'no'})
