// Test Jumper ŌĆö PostMessage-based DOM Testing
class IDETestBridge {
    constructor(iframe) {
        this.iframe = iframe;
        this.ready = false;
        this.pending = new Map();
        this.msgId = 0;
        
        window.addEventListener('message', (e) => {
            if (e.data?.id && this.pending.has(e.data.id)) {
                const { resolve, reject } = this.pending.get(e.data.id);
                this.pending.delete(e.data.id);
                if (e.data.error) reject(new Error(e.data.error));
                else resolve(e.data.result);
            }
            if (e.data?.type === 'rawrxd-ide-ready') {
                this.ready = true;
                console.log('[TestBridge] IDE signaled ready');
            }
        });
    }
    
    async call(cmd, args = [], timeout = 5000) {
        if (!this.ready && cmd !== 'elements') {
            await this.waitForReady();
        }
        
        return new Promise((resolve, reject) => {
            const id = ++this.msgId;
            this.pending.set(id, { resolve, reject });
            
            this.iframe.contentWindow.postMessage(
                { id, cmd, args }, 
                'http://localhost:11435'
            );
            
            setTimeout(() => {
                if (this.pending.has(id)) {
                    this.pending.delete(id);
                    reject(new Error(`Timeout: ${cmd}`));
                }
            }, timeout);
        });
    }
    
    waitForReady() {
        return new Promise((resolve) => {
            if (this.ready) return resolve();
            const check = setInterval(() => {
                if (this.ready) {
                    clearInterval(check);
                    resolve();
                }
            }, 100);
            setTimeout(() => { clearInterval(check); resolve(); }, 3000);
        });
    }
}

